    27→data class PlayerUiState(
    28→    val subtitles: List<SubtitleCue> = emptyList(),
    29→    val wordTimings: List<WordTimestamp> = emptyList(),
    30→    val currentCueIndex: Int = -1,
    31→    val currentPositionMs: Long = 0,
    32→    val mode: String = "learn", // "learn" or "dictation"
    33→    val currentLang: String = "en",
    34→    val statusText: String = "加载中...",
    35→    val isTranscribing: Boolean = false,
    36→    // Word card
    37→    val showWordCard: Boolean = false,
    38→    val wordCardData: WordCardData? = null,
    39→    val currentSentence: String = "",
    40→    // AI analysis
    41→    val aiAnalysisResult: String? = null,
    42→    val isAnalyzing: Boolean = false,
    43→    // Dictation
    44→    val dictationIndex: Int = 0
    45→)
    46→
    47→@HiltViewModel
    48→class PlayerViewModel @Inject constructor(
    49→    application: Application,
    50→    private val favoriteRepository: FavoriteRepository,
    51→    private val aiConfigStore: AIConfigStore,
    52→    private val aiService: AIService,
    53→    private val dictionaryService: DictionaryService,
    54→    private val whisperService: WhisperService
    55→) : AndroidViewModel(application) {
    56→
    57→    private val _uiState = MutableStateFlow(PlayerUiState())
    58→    val uiState: StateFlow<PlayerUiState> = _uiState.asStateFlow()
    59→
    60→    private var tts: TextToSpeech? = null
    61→    private val json = Json { ignoreUnknownKeys = true }
    62→
    63→    init {
    64→        tts = TextToSpeech(application) { status ->
    65→            if (status == TextToSpeech.SUCCESS) {
    66→                tts?.language = Locale.US
    67→            }
    68→        }
    69→    }
    70→
    71→    fun loadSubtitles(videoPath: String, subtitlePath: String?) {
    72→        viewModelScope.launch(Dispatchers.IO) {
    73→            // Try loading VTT subtitle
    74→            val vttPath = subtitlePath ?: findExistingSubtitle(videoPath)
    75→            if (vttPath != null) {
    76→                val file = File(vttPath)
    77→                if (file.exists()) {
    78→                    val content = file.readText()
    79→                    val subs = VttParser.parse(content)
    80→                    if (subs.isNotEmpty()) {
    81→                        _uiState.update { it.copy(
    82→                            subtitles = subs,
    83→                            statusText = "已加载 ${subs.size} 条字幕"
    84→                        )}
    85→                        // Load word timestamps if available
    86→                        loadWordTimestamps(vttPath)
    87→                        return@launch
    88→                    }
    89→                }
    90→            }
    91→            _uiState.update { it.copy(statusText = "无字幕文件，请在 AI 设置中配置 Groq Whisper 后重新转录") }
    92→        }
    93→    }
    94→
    95→    private fun findExistingSubtitle(videoPath: String): String? {
    96→        val base = videoPath.substringBeforeLast(".")
    97→        for (ext in listOf(".vtt", ".srt")) {
    98→            val f = File(base + ext)
    99→            if (f.exists()) return f.absolutePath
   100→        }
   101→        // Check with language suffix
   102→        val dir = File(videoPath).parentFile ?: return null
   103→        val name = File(videoPath).nameWithoutExtension
   104→        dir.listFiles()?.forEach { f ->
   105→            if (f.name.startsWith(name) && f.extension == "vtt") return f.absolutePath
   106→        }
   107→        return null
   108→    }
   109→
   110→    private fun loadWordTimestamps(vttPath: String) {
   111→        val wtsPath = vttPath.replace(Regex("\\.vtt$"), ".wordts.json")
   112→        val wtsFile = File(wtsPath)
   113→        if (wtsFile.exists()) {
   114→            try {
   115→                val timings: List<WordTimestamp> = json.decodeFromString(wtsFile.readText())
   116→                _uiState.update { it.copy(wordTimings = timings) }
   117→            } catch (_: Exception) {}
   118→        }
   119→    }
   120→
   121→    /** Called every 30ms from the player to sync subtitles */
   122→    fun updatePosition(positionMs: Long) {
   123→        _uiState.update { it.copy(currentPositionMs = positionMs) }
   124→        val subs = _uiState.value.subtitles
   125→        if (subs.isEmpty()) return
   126→
   127→        // Binary search for current cue (ported from renderer.js)
   128→        var lo = 0; var hi = subs.size - 1; var idx = -1
   129→        while (lo <= hi) {
   130→            val mid = (lo + hi) ushr 1
   131→            when {
   132→                positionMs < subs[mid].startMs -> hi = mid - 1
   133→                positionMs > subs[mid].endMs -> lo = mid + 1
   134→                else -> { idx = mid; break }
   135→            }
   136→        }
   137→        // Gap handling: find next cue within 0.5s
   138→        if (idx < 0) {
   139→            for (i in subs.indices) {
   140→                if (subs[i].startMs > positionMs) {
   141→                    idx = if (subs[i].startMs - positionMs < 500) i else if (i > 0) i - 1 else 0
   142→                    break
   143→                }
   144→            }
   145→            if (idx < 0) idx = subs.size - 1
   146→        }
   147→
   148→        if (idx != _uiState.value.currentCueIndex) {
   149→            _uiState.update { it.copy(
   150→                currentCueIndex = idx,
   151→                currentSentence = subs[idx].text,
   152→                showWordCard = false,
   153→                aiAnalysisResult = null
   154→            )}
   155→        }
   156→    }
   157→
   158→    /** Retranscribe - 使用分段转录支持大文件 */
   159→    fun retranscribe(videoPath: String) {
   160→        viewModelScope.launch(Dispatchers.IO) {
   161→            // Delete existing subtitle files
   162→            val base = videoPath.substringBeforeLast(".")
   163→            listOf(".vtt", ".wordts.json").forEach { ext ->
   164→                val f = File(base + ext)
   165→                if (f.exists()) f.delete()
   166→            }
   167→            // Also check language-suffixed vtt
   168→            File(videoPath).parentFile?.listFiles()?.forEach { f ->
   169→                val name = File(videoPath).nameWithoutExtension
   170→                if (f.name.startsWith(name) && (f.extension == "vtt" || f.name.endsWith(".wordts.json"))) {
   171→                    f.delete()
   172→                }
   173→            }
   174→
   175→            _uiState.update { it.copy(
   176→                subtitles = emptyList(),
   177→                wordTimings = emptyList(),
   178→                currentCueIndex = -1,
   179→                isTranscribing = true,
   180→                statusText = "正在准备转录..."
   181→            )}
   182→
   183→            val config = aiConfigStore.config.first()
   184→
   185→            // Check Groq API Key
   186→            val hasGroqKey = config.groqApiKey.isNotBlank() ||
   187→                             (config.provider == "groq" && config.apiKey.isNotBlank())
   188→
   189→            if (!hasGroqKey) {
   190→                _uiState.update { it.copy(isTranscribing = false, statusText = "请先在 AI 设置中配置 Groq Whisper API Key") }
   191→                return@launch
   192→            }
   193→
   194→            val videoFile = File(videoPath)
   195→
   196→            // 使用 Whisper 服务转录
   197→            val result = whisperService.transcribeGroq(
   198→                videoFile,
   199→                config
   200→            )
   201→
   202→            if (result != null && result.success && result.text.isNotBlank()) {
   203→                // Build VTT from word timestamps
   204→                val vttPath = base + ".vtt"
   205→                val wtsPath = base + ".wordts.json"
   206→                val vttBuilder = StringBuilder("WEBVTT\n\n")
   207→                val allWordTimings = mutableListOf<WordTimestamp>()
   208→
   209→                if (result.words.isNotEmpty()) {
   210→                    var curWords = mutableListOf<WordTimestamp>()
   211→                    for (wt in result.words) {
   212→                        curWords.add(wt)
   213→                        if (wt.w.trim().matches(Regex(".*[.!?。！？]$")) && curWords.isNotEmpty()) {
   214→                            val sentText = curWords.joinToString(" ") { it.w }
   215→                            val sStart = curWords.first().s
   216→                            val sEnd = curWords.last().e
   217→                            vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
   218→                            allWordTimings.addAll(curWords)
   219→                            curWords = mutableListOf()
   220→                        }
   221→                    }
   222→                    if (curWords.isNotEmpty()) {
   223→                        val sentText = curWords.joinToString(" ") { it.w }
   224→                        val sStart = curWords.first().s
   225→                        val sEnd = curWords.last().e
   226→                        vttBuilder.append("${VttParser.formatVtt(sStart)} --> ${VttParser.formatVtt(sEnd)}\n$sentText\n\n")
   227→                        allWordTimings.addAll(curWords)
   228→                    }
   229→                }
   230→
   231→                // Save files
   232→                File(vttPath).writeText(vttBuilder.toString())
   233→                if (allWordTimings.isNotEmpty()) {
   234→                    File(wtsPath).writeText(json.encodeToString(kotlinx.serialization.builtins.ListSerializer(WordTimestamp.serializer()), allWordTimings))
   235→                }
   236→
   237→                // Reload
   238→                val subs = VttParser.parse(vttBuilder.toString())
   239→                _uiState.update { it.copy(
   240→                    subtitles = subs,
   241→                    wordTimings = allWordTimings,
   242→                    isTranscribing = false,
   243→                    statusText = "转录完成，共 ${subs.size} 条字幕"
   244→                )}
   245→            } else {
   246→                _uiState.update { it.copy(isTranscribing = false, statusText = result?.error ?: "转录失败") }
   247→            }
   248→        }
   249→    }
   250→
   251→    fun setMode(mode: String) {
   252→        _uiState.update { it.copy(mode = mode, dictationIndex = _uiState.value.currentCueIndex.coerceAtLeast(0)) }
   253→    }
   254→
   255→    fun setLang(lang: String) {
   256→        _uiState.update { it.copy(currentLang = lang) }
   257→        val locale = LANGUAGES.find { it.code == lang }?.ttsLocale ?: "en-US"
   258→        tts?.language = Locale.forLanguageTag(locale)
   259→    }
   260→
   261→    /** Look up a word - ported from renderer.js showWordInline() */
   262→    fun lookupWord(word: String) {
   263→        _uiState.update { it.copy(showWordCard = true, wordCardData = WordCardData(word = word, translation = "查询中...")) }
   264→        speak(word)
   265→
   266→        viewModelScope.launch(Dispatchers.IO) {
   267→            val lang = _uiState.value.currentLang
   268→            val context = _uiState.value.currentSentence
   269→
   270→            // Parallel lookups
   271→            val aiConfig = aiConfigStore.config.first()
   272→            val aiTransPromise = launch { aiTranslateWord(word, context, lang, aiConfig) }
   273→
   274→            val cardData = when (lang) {
   275→                "en" -> {
   276→                    val online = dictionaryService.lookupEnglish(word)
   277→                    val translation = dictionaryService.translate(word, "en")
   278→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   279→                    WordCardData(
   280→                        word = word,
   281→                        phonetic = online?.phonetic ?: "",
   282→                        translation = aiTrans ?: translation ?: online?.translation ?: "未找到释义",
   283→                        definitions = online?.definitions ?: emptyList(),
   284→                        examples = online?.examples ?: emptyList()
   285→                    )
   286→                }
   287→                "ja" -> {
   288→                    val online = dictionaryService.lookupJapanese(word)
   289→                    val translation = dictionaryService.translate(word, "ja")
   290→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   291→                    WordCardData(
   292→                        word = word,
   293→                        phonetic = online?.phonetic ?: "",
   294→                        translation = aiTrans ?: translation ?: "未找到释义",
   295→                        definitions = online?.definitions ?: emptyList()
   296→                    )
   297→                }
   298→                else -> {
   299→                    val translation = dictionaryService.translate(word, lang)
   300→                    val aiTrans = aiTranslateWord(word, context, lang, aiConfig)
   301→                    WordCardData(
   302→                        word = word,
   303→                        translation = aiTrans ?: translation ?: "未找到释义"
   304→                    )
   305→                }
   306→            }
   307→            _uiState.update { it.copy(wordCardData = cardData) }
   308→        }
   309→    }
   310→
   311→    private suspend fun aiTranslateWord(word: String, context: String, lang: String, config: AIConfig): String? {
   312→        val langName = LANGUAGES.find { it.code == lang }?.name ?: "英语"
   313→        val prompt = "将${langName}「${word}」翻译为中文。${if (context.isNotBlank()) "语境:\"$context\"。" else ""}只回复中文释义，多义项用/分隔，不要音译。"
   314→        return aiService.chat(config, prompt)
   315→    }
   316→
   317→    fun hideWordCard() { _uiState.update { it.copy(showWordCard = false) } }
   318→
   319→    /** AI analyze sentence - ported from main.js ai-analyze-sentence */
   320→    fun analyzeSentence() {
   321→        val sentence = _uiState.value.currentSentence
   322→        if (sentence.isBlank()) return
   323→        _uiState.update { it.copy(isAnalyzing = true, aiAnalysisResult = "🤖 AI分析中...") }
   324→
   325→        viewModelScope.launch(Dispatchers.IO) {
   326→            val lang = _uiState.value.currentLang
   327→            val langName = LANGUAGES.find { it.code == lang }?.name ?: lang
   328→            val config = aiConfigStore.config.first()
   329→            val prompt = """分析${langName}句子："$sentence"
   330→【翻译】中文翻译
   331→【语法】1-2个关键语法点
   332→【重点词汇】2-3个重要词汇及释义"""
   333→            val result = aiService.chat(config, prompt)
   334→            _uiState.update { it.copy(
   335→                isAnalyzing = false,
   336→                aiAnalysisResult = result ?: "AI未配置或请求失败，请在设置中配置API Key"
   337→            )}
   338→        }
   339→    }
   340→
   341→    /** Favorite operations */
   342→    suspend fun isFavorite(word: String): Boolean {
   343→        return favoriteRepository.isFavorite(word, _uiState.value.currentLang)
   344→    }
   345→
   346→    fun toggleFavorite(word: String, phonetic: String = "", translation: String = "") {
   347→        viewModelScope.launch {
   348→            val lang = _uiState.value.currentLang
   349→            if (favoriteRepository.isFavorite(word, lang)) {
   350→                favoriteRepository.remove(word, lang)
   351→            } else {
   352→                favoriteRepository.add(word, lang, phonetic, translation, _uiState.value.currentSentence)
   353→            }
   354→        }
   355→    }
   356→
   357→    /** TTS */
   358→    fun speak(text: String) {
   359→        tts?.speak(text, TextToSpeech.QUEUE_FLUSH, null, "word_tts")
   360→    }
   361→
   362→    /** Dictation */
   363→    fun nextDictation() {
   364→        val nextIdx = (_uiState.value.dictationIndex + 1).coerceAtMost(_uiState.value.subtitles.size - 1)
   365→        _uiState.update { it.copy(dictationIndex = nextIdx) }
   366→    }
   367→
   368→    /** Get aligned word timings for current cue */
   369→    fun getAlignedTimings(words: List<String>): List<WordTimestamp?> {
   370→        val state = _uiState.value
   371→        val cueIdx = state.currentCueIndex
   372→        if (cueIdx < 0 || cueIdx >= state.subtitles.size || state.wordTimings.isEmpty()) {
   373→            return List(words.size) { null }
   374→        }
   375→        val cue = state.subtitles[cueIdx]
   376→        return WordAligner.alignWords(words, state.wordTimings, cue.startMs / 1000.0, cue.endMs / 1000.0)
   377→    }
   378→
   379→    override fun onCleared() {
   380→        tts?.shutdown()
   381→        super.onCleared()
   382→    }
   383→}
