   317→/**
   318→ * 下载进度卡片组件
   319→ */
   320→@Composable
   321→private fun DownloadProgressCard(
   322→    task: DownloadTask,
   323→    onCancel: () -> Unit,
   324→    formatFileSize: (Long) -> String,
   325→    formatSpeed: (Long) -> String,
   326→    formatRemainingTime: (Long) -> String,
   327→    getStatusText: (DownloadStatus) -> String
   328→) {
   329→    Card(
   330→        modifier = Modifier.fillMaxWidth(),
   331→        colors = CardDefaults.cardColors(
   332→            containerColor = when (task.status) {
   333→                DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.errorContainer
   334→                else -> MaterialTheme.colorScheme.primaryContainer
   335→            }
   336→        )
   337→    ) {
   338→        Column(modifier = Modifier.padding(16.dp)) {
   339→            // 标题和状态
   340→            Row(
   341→                modifier = Modifier.fillMaxWidth(),
   342→                horizontalArrangement = Arrangement.SpaceBetween,
   343→                verticalAlignment = Alignment.CenterVertically
   344→            ) {
   345→                Column(Modifier.weight(1f)) {
   346→                    Text(
   347→                        task.title,
   348→                        style = MaterialTheme.typography.titleSmall,
   349→                        maxLines = 1,
   350→                        overflow = TextOverflow.Ellipsis
   351→                    )
   352→                    Text(
   353→                        getStatusText(task.status),
   354→                        style = MaterialTheme.typography.bodySmall,
   355→                        color = when (task.status) {
   356→                            DownloadStatus.FAILED, DownloadStatus.CANCELLED -> MaterialTheme.colorScheme.error
   357→                            else -> MaterialTheme.colorScheme.onPrimaryContainer
   358→                        }
   359→                    )
   360→                }
   361→
   362→                // 取消按钮
   363→                if (task.status == DownloadStatus.DOWNLOADING || task.status == DownloadStatus.FETCHING_INFO) {
   364→                    IconButton(onClick = onCancel) {
   365→                        Icon(Icons.Default.Close, "取消", tint = MaterialTheme.colorScheme.error)
   366→                    }
   367→                }
   368→            }
   369→
   370→            Spacer(Modifier.height(12.dp))
   371→
   372→            // 进度条
   373→            if (task.status == DownloadStatus.DOWNLOADING) {
   374→                Column {
   375→                    Row(
   376→                        modifier = Modifier.fillMaxWidth(),
   377→                        horizontalArrangement = Arrangement.SpaceBetween
   378→                    ) {
   379→                        Text(
   380→                            "${task.progress}%",
   381→                            style = MaterialTheme.typography.bodySmall
   382→                        )
   383→                        if (task.speed > 0) {
   384→                            Text(
   385→                                formatSpeed(task.speed),
   386→                                style = MaterialTheme.typography.bodySmall,
   387→                                color = MaterialTheme.colorScheme.primary
   388→                            )
   389→                        }
   390→                    }
   391→
   392→                    Spacer(Modifier.height(4.dp))
   393→
   394→                    LinearProgressIndicator(
   395→                        progress = { task.progress / 100f },
   396→                        modifier = Modifier.fillMaxWidth(),
   397→                        color = MaterialTheme.colorScheme.primary
   398→                    )
   399→
   400→                    // 文件大小和剩余时间
   401→                    if (task.totalBytes > 0) {
   402→                        Spacer(Modifier.height(4.dp))
   403→                        Row(
   404→                            modifier = Modifier.fillMaxWidth(),
   405→                            horizontalArrangement = Arrangement.SpaceBetween
   406→                        ) {
   407→                            Text(
   408→                                "${formatFileSize(task.bytesDownloaded)} / ${formatFileSize(task.totalBytes)}",
   409→                                style = MaterialTheme.typography.bodySmall,
   410→                                color = MaterialTheme.colorScheme.onPrimaryContainer
   411→                            )
   412→                            if (task.remainingTime > 0 && task.speed > 0) {
   413→                                Text(
   414→                                    "剩余 ${formatRemainingTime(task.remainingTime)}",
   415→                                    style = MaterialTheme.typography.bodySmall,
   416→                                    color = MaterialTheme.colorScheme.onPrimaryContainer
   417→                                )
   418→                            }
   419→                        }
   420→                    }
   421→                }
   422→            } else if (task.status == DownloadStatus.FETCHING_INFO) {
   423→                Row(
   424→                    modifier = Modifier.fillMaxWidth(),
   425→                    verticalAlignment = Alignment.CenterVertically
   426→                ) {
   427→                    CircularProgressIndicator(
   428→                        modifier = Modifier.size(20.dp),
   429→                        strokeWidth = 2.dp
   430→                    )
   431→                    Spacer(Modifier.width(8.dp))
   432→                    Text(
   433→                        "正在解析视频信息...",
   434→                        style = MaterialTheme.typography.bodySmall,
   435→                        color = MaterialTheme.colorScheme.onPrimaryContainer
   436→                    )
   437→                }
   438→            } else if (task.status == DownloadStatus.FAILED) {
   439→                Row(
   440→                    modifier = Modifier.fillMaxWidth(),
   441→                    verticalAlignment = Alignment.CenterVertically
   442→                ) {
   443→                    Icon(
   444→                        Icons.Default.Error,
   445→                        contentDescription = null,
   446→                        tint = MaterialTheme.colorScheme.error,
   447→                        modifier = Modifier.size(20.dp)
   448→                    )
   449→                    Spacer(Modifier.width(8.dp))
   450→                    Text(
   451→                        task.errorMessage ?: "下载失败",
   452→                        style = MaterialTheme.typography.bodySmall,
   453→                        color = MaterialTheme.colorScheme.error
   454→                    )
   455→                }
   456→            } else if (task.status == DownloadStatus.COMPLETED) {
   457→                Row(
   458→                    modifier = Modifier.fillMaxWidth(),
   459→                    verticalAlignment = Alignment.CenterVertically
   460→                ) {
   461→                    Icon(
   462→                        Icons.Default.CheckCircle,
   463→                        contentDescription = null,
   464→                        tint = MaterialTheme.colorScheme.primary,
   465→                        modifier = Modifier.size(20.dp)
   466→                    )
   467→                    Spacer(Modifier.width(8.dp))
   468→                    Text(
   469→                        "下载完成",
   470→                        style = MaterialTheme.typography.bodySmall,
   471→                        color = MaterialTheme.colorScheme.primary
   472→                    )
   473→                }
   474→            }
   475→        }
   476→    }
   477→}
